"use client";

import { useState } from "react";
import { useQuery } from "@tanstack/react-query";

type Tool = {
  name: string;
  description: string;
  args_schema: any;
  function_name: string;
  file_path: string;
  module_name: string;
};

export default function Home() {
  const [selectedTool, setSelectedTool] = useState<Tool | null>(null);
  const [params, setParams] = useState<Record<string, string>>({});
  const [result, setResult] = useState<any>(null);
  const [loading, setLoading] = useState(false);
  const [syncing, setSyncing] = useState(false);
  const [testSuccess, setTestSuccess] = useState(false);

  const { data, isLoading, error } = useQuery({
    queryKey: ["tools"],
    queryFn: async () => {
      const res = await fetch("http://localhost:8081/api/tools");
      if (!res.ok) throw new Error("Failed to load tools");
      const json = await res.json();
      return json.tools as Tool[];
    },
  });

  const tools = data || [];

  const handleRun = async () => {
    if (!selectedTool) return;
    setLoading(true);
    setTestSuccess(false);
    
    try {
      const res = await fetch(`http://localhost:8081/api/tools/${selectedTool.name}/run`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ params }),
      });
      const data = await res.json();
      setResult(data);
      if (res.ok && !data.error) {
        setTestSuccess(true);
      }
    } catch (err: any) {
      setResult({ error: err.message || "Failed to execute" });
    } finally {
      setLoading(false);
    }
  };

  const handleSync = async () => {
    if (!selectedTool) return;
    setSyncing(true);
    try {
      const res = await fetch(`http://localhost:8081/api/tools/${selectedTool.name}/sync`, {
        method: "POST",
      });
      if (res.ok) {
        alert("Zsynchronizowano z Axon!");
      } else {
        const err = await res.json();
        alert(`Błąd: ${err.detail}`);
      }
    } catch (err: any) {
      alert("Błąd synchronizacji");
    } finally {
      setSyncing(false);
    }
  };

  // --- RENDERING ---

  if (!selectedTool) {
    return (
      <div className="min-h-screen bg-neutral-950 text-white p-8">
        <div className="max-w-6xl mx-auto">
          <header className="mb-8">
            <h1 className="text-3xl font-bold mb-2 text-white">Rejestr Funkcji</h1>
            <p className="text-neutral-400">Axon Internal Tools Dev Env — Single Source of Truth</p>
          </header>

          {isLoading && <div className="text-center py-20 text-neutral-500">Ładowanie narzędzi...</div>}
          {error && <div className="text-center py-20 text-red-500 bg-red-500/10 rounded-lg border border-red-500/20">Wystąpił błąd podczas ładowania funkcji.</div>}
          
          {!isLoading && !error && (
            <div className="overflow-hidden rounded-xl border border-neutral-800 bg-neutral-900/50">
              <table className="w-full text-left border-collapse">
                <thead>
                  <tr className="bg-neutral-900 border-b border-neutral-800">
                    <th className="px-6 py-4 text-sm font-semibold text-neutral-300">Nazwa</th>
                    <th className="px-6 py-4 text-sm font-semibold text-neutral-300">Opis</th>
                    <th className="px-6 py-4 text-sm font-semibold text-neutral-300">Moduł</th>
                    <th className="px-6 py-4 text-sm font-semibold text-neutral-300">Plik</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-neutral-800">
                  {tools.length === 0 ? (
                    <tr>
                      <td colSpan={4} className="px-6 py-12 text-center text-neutral-500 italic">Brak wykrytych funkcji (@tool) w src/axon_tools/tools/</td>
                    </tr>
                  ) : (
                    tools.map((t) => (
                      <tr 
                        key={t.name} 
                        onClick={() => {
                          setSelectedTool(t);
                          setParams({});
                          setResult(null);
                          setTestSuccess(false);
                        }}
                        className="hover:bg-neutral-800/50 cursor-pointer transition-colors group"
                      >
                        <td className="px-6 py-4">
                          <div className="font-medium text-blue-400 group-hover:text-blue-300">{t.name}</div>
                        </td>
                        <td className="px-6 py-4">
                          <div className="text-sm text-neutral-400 line-clamp-1">{t.description || "Brak opisu"}</div>
                        </td>
                        <td className="px-6 py-4">
                          <code className="text-xs bg-neutral-800 px-2 py-1 rounded text-neutral-300">{t.module_name}</code>
                        </td>
                        <td className="px-6 py-4 text-sm text-neutral-500">
                          {t.file_path}
                        </td>
                      </tr>
                    ))
                  )}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-screen bg-neutral-950 text-white overflow-hidden">
      {/* Detail Header */}
      <header className="h-16 border-b border-neutral-800 flex items-center px-6 justify-between shrink-0">
        <div className="flex items-center gap-4">
          <button 
            onClick={() => setSelectedTool(null)}
            className="p-2 hover:bg-neutral-800 rounded-md transition-colors text-neutral-400 hover:text-white"
            title="Wróć do listy"
          >
            ← Wstecz
          </button>
          <div>
            <h2 className="font-bold text-lg leading-tight">{selectedTool.name}</h2>
            <p className="text-xs text-neutral-500 font-mono">{selectedTool.module_name}</p>
          </div>
        </div>
        <div className="flex gap-2">
          <button
            onClick={handleRun}
            disabled={loading}
            className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-md font-medium text-sm disabled:opacity-50 transition-all shadow-lg shadow-blue-900/20"
          >
            {loading ? "Wykonywanie..." : "Uruchom Test"}
          </button>
          
          <button
            onClick={handleSync}
            disabled={!testSuccess || syncing}
            className={`px-4 py-2 rounded-md font-medium text-sm transition-all ${
              testSuccess
                ? "bg-green-600 hover:bg-green-700 text-white shadow-lg shadow-green-900/20"
                : "bg-neutral-800 text-neutral-500 cursor-not-allowed"
            }`}
          >
            {syncing ? "Wysyłanie..." : "Synchronizuj z Axon"}
          </button>
        </div>
      </header>

      {/* Main Area - Split View */}
      <div className="flex flex-1 overflow-hidden">
        {/* Left - Input Form */}
        <div className="w-1/2 border-r border-neutral-800 p-8 overflow-y-auto bg-neutral-900/20">
          <div className="max-w-xl mx-auto">
            <h3 className="text-sm font-semibold uppercase tracking-wider text-neutral-500 mb-6">Parametry wejściowe</h3>
            <div className="space-y-6">
              {selectedTool.args_schema?.properties ? (
                Object.entries(selectedTool.args_schema.properties).map(([key, prop]: [string, any]) => (
                  <div key={key}>
                    <label className="block text-sm font-medium text-neutral-300 mb-2">
                      {key} {selectedTool.args_schema.required?.includes(key) && <span className="text-red-500">*</span>}
                    </label>
                    <div className="relative">
                      <input
                        type="text"
                        className="w-full bg-neutral-900 border border-neutral-700 rounded-lg px-4 py-3 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500/50 focus:border-blue-500 transition-all"
                        placeholder={prop.type || "string"}
                        value={params[key] || ""}
                        onChange={(e) => setParams({ ...params, [key]: e.target.value })}
                      />
                      <span className="absolute right-3 top-3 text-[10px] text-neutral-600 font-mono uppercase bg-neutral-950 px-1.5 py-0.5 rounded">
                        {prop.type || "any"}
                      </span>
                    </div>
                  </div>
                ))
              ) : (
                <p className="text-sm text-neutral-500 italic">Brak zdefiniowanych argumentów.</p>
              )}
            </div>
            
            <div className="mt-10 p-4 bg-neutral-900/50 border border-neutral-800 rounded-lg">
              <h4 className="text-xs font-semibold text-neutral-400 mb-2 uppercase tracking-widest">Opis funkcji</h4>
              <p className="text-sm text-neutral-300 leading-relaxed italic whitespace-pre-wrap">
                {selectedTool.description || "Brak dokumentacji docstring."}
              </p>
            </div>
          </div>
        </div>

        {/* Right - Output Console */}
        <div className="w-1/2 bg-[#080808] flex flex-col font-mono relative overflow-hidden">
          <div className="flex items-center justify-between px-6 py-3 bg-neutral-900/50 border-b border-neutral-800 shrink-0">
            <h3 className="text-xs font-bold text-neutral-400 uppercase tracking-widest">Konsola Wyjściowa</h3>
            {result && (
              <span className="text-[10px] text-neutral-500">
                Czas: <span className={result.execution_time_ms > 1000 ? "text-orange-400" : "text-green-400"}>{result.execution_time_ms} ms</span>
              </span>
            )}
          </div>
          
          <div className="flex-1 overflow-y-auto p-6 space-y-6 text-sm">
            {!result && (
              <div className="h-full flex items-center justify-center text-neutral-700 italic">
                Czekam na uruchomienie testu...
              </div>
            )}
            
            {result && (
              <>
                {result.error && (
                  <div className="bg-red-950/20 border border-red-900/50 p-4 rounded-lg">
                    <h4 className="text-red-500 font-bold mb-2 text-xs uppercase">Błąd wykonania:</h4>
                    <pre className="text-red-400 whitespace-pre-wrap text-xs leading-relaxed">{result.error}</pre>
                  </div>
                )}
                
                {result.logs && (
                  <div className="bg-neutral-900/30 p-4 rounded-lg border border-neutral-800">
                    <h4 className="text-neutral-500 font-bold mb-2 text-xs uppercase italic">Standard Output (logs):</h4>
                    <pre className="text-neutral-400 whitespace-pre-wrap text-xs leading-relaxed">{result.logs}</pre>
                  </div>
                )}

                {!result.error && result.result !== undefined && (
                  <div className="bg-green-950/10 border border-green-900/30 p-4 rounded-lg">
                    <h4 className="text-green-500 font-bold mb-2 text-xs uppercase">Zwrócona wartość:</h4>
                    <pre className="text-green-400 whitespace-pre-wrap text-lg font-bold">
                      {typeof result.result === "object" ? JSON.stringify(result.result, null, 2) : String(result.result)}
                    </pre>
                  </div>
                )}
              </>
            )}
          </div>
          
          {/* Subtle gradient overlay at top/bottom */}
          <div className="absolute inset-x-0 top-10 h-8 bg-gradient-to-b from-[#080808] to-transparent pointer-events-none opacity-50"></div>
          <div className="absolute inset-x-0 bottom-0 h-8 bg-gradient-to-t from-[#080808] to-transparent pointer-events-none opacity-50"></div>
        </div>
      </div>
    </div>
  );
}
